// gen_mcpdocs reads all schema YAML files and the embedded default config to
// generate docs/tools-reference.md — a complete auto-generated reference page
// for every MCP tool group and its operations.
//
// Overrides from internal/config/default_mcp_config.yaml are resolved and
// shown inline so the rendered doc reflects what the agent actually receives.
//
// Usage: go run scripts/gen_mcpdocs/main.go
//
// This is called by `make generate-docs` and re-run in CI on every schema change.
package main

import (
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"text/template"

	"github.com/FabianSchurig/bitbucket-cli/internal/config"
	"github.com/FabianSchurig/bitbucket-cli/scripts/internal/spec"
)

// outputPath is where the generated reference doc is written.
const outputPath = "docs/tools-reference.md"

// schemaGlob matches all self-contained schema files.
const schemaGlob = "schema/*-schema.yaml"

// defaultConfigPath is read to resolve overrides shown in the doc.
const defaultConfigPath = "internal/config/default_mcp_config.yaml"

// ─── Data types ───────────────────────────────────────────────────────────────

// ToolDoc holds the data for one tool group section in the rendered doc.
type ToolDoc struct {
	ToolName    string    // e.g., "bitbucket_pr"
	Description string    // group-level description (overridden if configured)
	Ignored     bool      // true when the default config hides this tool
	Operations  []OpDoc
}

// OpDoc holds the data for one operation row.
type OpDoc struct {
	OperationID string
	Method      string
	Summary     string
	Description string // may be overridden by config
	Overridden  bool   // true when an override applies
}

// ─── Template ─────────────────────────────────────────────────────────────────

const docTemplate = `<!-- Code generated by scripts/gen_mcpdocs/main.go DO NOT EDIT. -->
<!-- Re-generate with: go run scripts/gen_mcpdocs/main.go              -->

# MCP Tool Reference

This page is auto-generated from the Bitbucket OpenAPI schemas and the
[default_mcp_config.yaml](../internal/config/default_mcp_config.yaml).

> **Descriptions marked with ✏️** are overridden by the default configuration to
> give the LLM more actionable guidance. Override any of them in a local
> ` + "`" + `mcp_config.yaml` + "`" + ` to tailor the agent's behaviour for your workspace.

---
{{range .}}
## ` + "`" + `{{.ToolName}}` + "`" + `{{if .Ignored}} *(hidden by default)*{{end}}

{{.Description}}
{{if not .Ignored}}
| Operation | Method | Description |
|-----------|--------|-------------|
{{- range .Operations}}
| ` + "`" + `{{.OperationID}}` + "`" + ` | ` + "`" + `{{.Method}}` + "`" + ` | {{oneliner .Description}}{{if .Overridden}} ✏️{{end}} |
{{- end}}
{{end}}
---
{{end}}`

// ─── Helpers ─────────────────────────────────────────────────────────────────

// oneliner returns the first non-empty line of a multi-line string.
func oneliner(s string) string {
	s = strings.TrimSpace(s)
	lines := strings.SplitN(s, "\n", 2)
	first := strings.TrimSpace(lines[0])
	// Strip trailing period-only markdown noise.
	return first
}

var funcMap = template.FuncMap{
	"oneliner": oneliner,
	"not": func(b bool) bool { return !b },
}

// ─── Main ─────────────────────────────────────────────────────────────────────

func main() {
	// Load default config so we can resolve overrides and ignored tools.
	cfg, err := config.Load(defaultConfigPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "loading default config: %v\n", err)
		os.Exit(1)
	}

	// Collect all schema files.
	matches, err := filepath.Glob(schemaGlob)
	if err != nil || len(matches) == 0 {
		fmt.Fprintf(os.Stderr, "no schema files found at %s\n", schemaGlob)
		os.Exit(1)
	}
	sort.Strings(matches)

	var tools []ToolDoc
	for _, schemaPath := range matches {
		schema, err := spec.LoadSchema(schemaPath)
		if err != nil {
			fmt.Fprintf(os.Stderr, "loading %s: %v\n", schemaPath, err)
			os.Exit(1)
		}

		_, use, short, _ := spec.CommandMeta(schema.Info)
		toolName := "bitbucket_" + use

		operations := spec.BuildOperations(schema)

		override := cfg.ToolOverrides[toolName]

		// Resolve group description: prefer override, fall back to schema short.
		groupDesc := short
		if override.Description != "" {
			groupDesc = strings.TrimSpace(override.Description)
		}

		var opDocs []OpDoc
		for _, op := range operations {
			desc := op.Description
			overridden := false
			if override.Operations != nil {
				if opOverride, ok := override.Operations[op.OperationID]; ok && opOverride.Description != "" {
					desc = strings.TrimSpace(opOverride.Description)
					overridden = true
				}
			}
			// Fall back to Summary when Description is empty (common in the schema).
			if strings.TrimSpace(desc) == "" {
				desc = op.Summary
			}
			opDocs = append(opDocs, OpDoc{
				OperationID: op.OperationID,
				Method:      op.Method,
				Summary:     op.Summary,
				Description: desc,
				Overridden:  overridden,
			})
		}

		tools = append(tools, ToolDoc{
			ToolName:    toolName,
			Description: groupDesc,
			Ignored:     cfg.IsToolIgnored(toolName),
			Operations:  opDocs,
		})
	}

	tmpl, err := template.New("mcp-docs").Funcs(funcMap).Parse(docTemplate)
	if err != nil {
		fmt.Fprintf(os.Stderr, "parsing template: %v\n", err)
		os.Exit(1)
	}

	f, err := os.Create(outputPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "creating %s: %v\n", outputPath, err)
		os.Exit(1)
	}
	defer f.Close()

	if err := tmpl.Execute(f, tools); err != nil {
		fmt.Fprintf(os.Stderr, "rendering template: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Generated %s (%d tool groups)\n", outputPath, len(tools))
}
